import{_ as a,o as t,c as s,ag as l}from"./chunks/framework.Lq6hU67C.js";const g=JSON.parse('{"title":"Layers and event log","description":"","frontmatter":{},"headers":[],"relativePath":"concepts/layers-and-event-log.md","filePath":"concepts/layers-and-event-log.md"}'),r={name:"concepts/layers-and-event-log.md"};function o(n,e,i,d,c,p){return t(),s("div",null,[...e[0]||(e[0]=[l('<h1 id="layers-and-event-log" tabindex="-1">Layers and event log <a class="header-anchor" href="#layers-and-event-log" aria-label="Permalink to &quot;Layers and event log&quot;">​</a></h1><p>Addressables Leak Detector uses two complementary mechanisms to track Addressables handles.</p><h2 id="layer-1-—-il-post-processor-call-site-capture" tabindex="-1">Layer 1 — IL Post-Processor (call-site capture) <a class="header-anchor" href="#layer-1-—-il-post-processor-call-site-capture" aria-label="Permalink to &quot;Layer 1 — IL Post-Processor (call-site capture)&quot;">​</a></h2><p>At compile time, Cecil injects calls to <code>HandleTracker</code> at Addressables <strong>load</strong> and <strong>release</strong> call sites in <strong>your</strong> assemblies (not inside the package itself).</p><p>Each injection records:</p><ul><li>Operation kind (LoadAsset, Instantiate, LoadScene, Release, etc.)</li><li>Source file and line number (default)</li><li>Optional full stack trace when <strong>Verbose</strong> mode is enabled</li></ul><p>Layer 1 answers: <strong>where was this handle loaded or released in user code?</strong></p><h2 id="layer-2-—-lifecycle-bridges-public-api" tabindex="-1">Layer 2 — Lifecycle bridges (public API) <a class="header-anchor" href="#layer-2-—-lifecycle-bridges-public-api" aria-label="Permalink to &quot;Layer 2 — Lifecycle bridges (public API)&quot;">​</a></h2><p>After a load is recorded, the runtime subscribes to public handle lifecycle signals:</p><ul><li><code>AsyncOperationHandle.Completed</code></li><li><code>AsyncOperationHandle.Destroyed</code></li></ul><p>On Addressables 2.2.2+, the global <code>RegisterDiagnosticCallback</code> API was removed from the public surface; per-handle events are the primary channel.</p><p>Layer 2 answers: <strong>when did the handle complete or get destroyed?</strong></p><h2 id="append-only-event-log" tabindex="-1">Append-only event log <a class="header-anchor" href="#append-only-event-log" aria-label="Permalink to &quot;Append-only event log&quot;">​</a></h2><p>All events are stored as immutable <code>HandleEventRecord</code> entries. The live handle registry is <strong>rebuilt</strong> from this stream — historical records are never edited or deleted in place.</p><p>Toolbar <strong>Clear</strong> resets the log and registry for a fresh session.</p><h2 id="what-ilpp-does-not-track" tabindex="-1">What ILPP does not track <a class="header-anchor" href="#what-ilpp-does-not-track" aria-label="Permalink to &quot;What ILPP does not track&quot;">​</a></h2><ul><li>Flow of a handle between methods (handles are structs — only creation and release call sites are captured).</li><li>Loads/releases inside excluded assemblies (see <a href="./../how-to/assembly-exclude-list.html">Assembly exclude list</a>).</li><li>Non-instrumented API overloads (see <a href="./../reference/supported-call-sites.html">Supported call sites</a>).</li></ul><h2 id="settings-bridge" tabindex="-1">Settings bridge <a class="header-anchor" href="#settings-bridge" aria-label="Permalink to &quot;Settings bridge&quot;">​</a></h2><p>Editor toggles (<strong>Recording</strong>, <strong>Verbose</strong>, assembly exclude list) are written to <code>Library/AddressablesLeakDetector/ilpp_settings.json</code> because EditorPrefs are unavailable during ILPP. Changing settings triggers recompile. See <a href="./../reference/ilpp-settings.html">ILPP settings</a>.</p><h2 id="see-also" tabindex="-1">See also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See also&quot;">​</a></h2><ul><li><a href="./handle-identity.html">Handle identity</a></li><li><a href="./../reference/il-limitations.html">IL patterns and limitations</a></li><li><a href="./../how-to/ilpp-diagnostics.html">ILPP diagnostics</a></li></ul>',21)])])}const u=a(r,[["render",o]]);export{g as __pageData,u as default};
